import React, { useEffect, useState } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext'; 
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme(); 
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_SYNC_ERROR");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Proceed with deletion?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) { toast.error("WIPE_FAILURE"); }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) { toast.error("EXPORT_FAILED"); }
  };

  useEffect(() => { fetchHistory(); }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      {/* --- Page Header --- */}
      <div style={headerRow}>
        <h2 style={headerStyle}>
            <Archive size={36} color="var(--accent-primary)"/> STRATEGY_VAULT
        </h2>
        <div style={vaultBadge}>
            <BarChart3 size={20} /> {history.length} NODES_STORED
        </div>
      </div>
      
      {/* --- List Section --- */}
      <div style={listStyle}>
        {history.map((item) => (
          <div key={item.id} className="vault-card" style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '25px' }}>
                <span style={dateTag}><Calendar size={20}/> {new Date(item.created_at).toLocaleDateString()}</span>
                <span style={riskTag}><ShieldCheck size={20}/> RISK: {item.risk_score}</span>
              </div>
              <div style={cardActions}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="Full Description"><Eye size={28}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Export PDF"><Download size={28}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Wipe"><Trash2 size={28}/></button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal}</h4>

            <div style={sectionBlock}>
              <p style={labelSmall}><AlignLeft size={16} style={{marginRight:'12px'}}/> MARKET_SUMMARY</p>
              <div className="markdown-vault">
                <ReactMarkdown>{item.summary}</ReactMarkdown>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* --- THEME FIXED MODAL --- */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={32}/></button>
            </div>
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              <div style={modalSectionStyle}>
                <p style={modalLabel}><AlignLeft size={18} style={{marginRight:'15px'}}/> AGENTIC_RATIONALE</p>
                <div className="markdown-vault">
                    <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .markdown-vault h1, .markdown-vault h2 { color: var(--accent-primary); font-size: 1.3rem; margin-top: 1.5rem; text-transform: uppercase; font-weight: 800; }
        .markdown-vault p { color: var(--text-primary); font-size: 1.15rem; line-height: 1.8; margin-bottom: 1.2rem; }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-5px); box-shadow: 0 15px 40px var(--shadow-color); }
        .reveal-node { animation: fadeIn 0.4s ease; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

/* --- Refined Theme Styles --- */
const containerStyle = { padding: '4rem 2rem', maxWidth: '1300px', margin: '0 auto' };
const headerRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4rem', borderBottom: '2px solid var(--surface-border)', paddingBottom: '2.5rem' };
const headerStyle = { display: 'flex', alignItems: 'center', gap: '25px', fontSize: '2.5rem', fontWeight: 900, color: 'var(--text-primary)', margin: 0 };
const vaultBadge = { fontSize: '1.1rem', color: 'var(--accent-primary)', fontWeight: 800, background: 'rgba(16,185,129,0.1)', padding: '12px 24px', borderRadius: '10px', border: '1px solid var(--surface-border)', display: 'flex', alignItems: 'center', gap: '15px' };

const listStyle = { display: 'flex', flexDirection: 'column', gap: '3rem' };
const cardStyle = { padding: '3.5rem', background: 'var(--bg-input, var(--nav-bg))', border: '2px solid var(--surface-border)', borderRadius: '32px' };

const cardMeta = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' };
const dateTag = { fontSize: '1.1rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '12px', fontWeight: 700 };
const riskTag = { fontSize: '1.1rem', color: 'var(--accent-primary)', fontWeight: 900, display: 'flex', alignItems: 'center', gap: '12px' };
const titleStyle = { fontSize: '2rem', fontWeight: 900, color: 'var(--text-primary)', margin: '0 0 2.5rem 0' };

const labelSmall = { fontSize: '0.9rem', fontWeight: 900, color: 'var(--text-muted)', letterSpacing: '0.2em', marginBottom: '1.5rem', display: 'flex', alignItems: 'center' };
const cardActions = { display: 'flex', gap: '25px' };
const iconBtn = { background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' };
const deleteBtn = { ...iconBtn, color: '#ef4444' };

/* --- FIXED THEME MODAL STYLES --- */
const modalOverlay = (isDark) => ({
  position: 'fixed',
  top: 0,
  left: 0,
  width: '100%',
  height: '100%',
  // Background adjusts based on mode
  background: isDark ? 'rgba(0, 0, 0, 0.9)' : 'rgba(255, 255, 255, 0.85)',
  backdropFilter: 'blur(20px)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  zIndex: 3000,
});

